const data = rows.filter(r => r.length >= header.length);

// Leading item-number token = first whitespace-delimited chunk of name,
// if it looks like a DesignFlow item_num_id (uppercase alnum, 9-13 chars, >=2 digits & >=3 letters)
const ITEM_RE = /^[A-Z0-9]{9,13}$/;
function leadingItemNo(name) {
  if (!name) return null;
  const tok = name.trim().split(/[\s\t]+/)[0];
  if (!ITEM_RE.test(tok)) return null;
  const digits = (tok.match(/\d/g) || []).length;
  const letters = (tok.match(/[A-Z]/g) || []).length;
  if (digits < 2 || letters < 3) return null;
  return tok;
}

