import fs from "node:fs";
import path from "node:path";

type ToolsConfig = {
  enabled_read_tools?: string[];
  enabled_write_tools?: string[];
};

const splitCsv = (value: string | undefined): string[] =>
  (value ?? "")
    .split(",")
    .map((part) => part.trim())
    .filter(Boolean);

export const loadToolConfig = (cwd: string): Set<string> => {
  const configPath = path.join(cwd, "tools-config.json");
  const raw = fs.existsSync(configPath) ? fs.readFileSync(configPath, "utf8") : "{}";
  const parsed = JSON.parse(raw) as ToolsConfig;

  const enabled = new Set<string>([
    ...(parsed.enabled_read_tools ?? []),
    ...(parsed.enabled_write_tools ?? []),
    ...splitCsv(process.env.DESIGNFLOW_MCP_ENABLED_TOOLS),
  ]);

  for (const disabled of splitCsv(process.env.DESIGNFLOW_MCP_DISABLED_TOOLS)) {
    enabled.delete(disabled);
  }

  return enabled;
};

