import { KEYWORD_TO_GROUPS, TOOL_GROUPS } from "./groups.js";
import { ALL_TOOL_DEFS } from "./tool-defs.js";
import type { ToolDef, ToolGroup, ToolSummary } from "../types.js";

export class ToolCatalog {
  private readonly enabled: Set<string>;
  private readonly tools: ToolDef[];
  private readonly byName: Map<string, ToolDef>;

  constructor(enabled: Set<string>) {
    this.enabled = enabled;
    this.tools = ALL_TOOL_DEFS.filter((tool) => enabled.has(tool.name));
    this.byName = new Map(this.tools.map((tool) => [tool.name, tool]));
  }

  listCapabilities(filters: { group?: ToolGroup; safety?: number; limit?: number }): ToolSummary[] {
    const limit = Math.min(Math.max(filters.limit ?? 20, 1), 100);
    return this.tools
      .filter((tool) => !filters.group || tool.group === filters.group)
      .filter((tool) => !filters.safety || tool.safety.tier === filters.safety)
      .slice(0, limit)
      .map(toSummary);
  }

  get(name: string): ToolDef | undefined {
    return this.byName.get(name);
  }

  search(query: string, limit = 8): ToolDef[] {
    const normalized = query.trim().toLowerCase();
    if (!normalized) {
      return this.tools.slice(0, limit);
    }

    const words = normalized.split(/\s+/).filter(Boolean);
    const exactGroup = TOOL_GROUPS.find((group) => group.name === normalized);

    const scored = this.tools
      .map((tool) => {
        const haystack = `${tool.name} ${tool.title} ${tool.description} ${tool.group}`.toLowerCase();
        const keywordGroups = new Set(words.flatMap((word) => KEYWORD_TO_GROUPS[word] ?? []));
        const keywordGroupMatch = keywordGroups.has(tool.group);

        if (exactGroup && tool.group !== exactGroup.name) {
          return { tool, score: 0 };
        }

        const allWordsMatch = words.every((word) => haystack.includes(word) || keywordGroups.has(tool.group));
        if (!allWordsMatch && !keywordGroupMatch) {
          return { tool, score: 0 };
        }

        let score = 0;
        for (const word of words) {
          if (tool.name.toLowerCase().includes(word)) score += 4;
          if (tool.title.toLowerCase().includes(word)) score += 3;
          if (tool.description.toLowerCase().includes(word)) score += 1;
          if (KEYWORD_TO_GROUPS[word]?.includes(tool.group)) score += 2;
        }
        if (exactGroup && tool.group === exactGroup.name) score += 10;
        return { tool, score };
      })
      .filter((entry) => entry.score > 0)
      .sort((a, b) => b.score - a.score || a.tool.name.localeCompare(b.tool.name));

    return scored.slice(0, Math.min(Math.max(limit, 1), 30)).map((entry) => entry.tool);
  }

  disabledNames(): string[] {
    return ALL_TOOL_DEFS.filter((tool) => !this.enabled.has(tool.name)).map((tool) => tool.name).sort();
  }
}

export const toSummary = (tool: ToolDef): ToolSummary => ({
  name: tool.name,
  title: tool.title,
  group: tool.group,
  safety: tool.safety,
  description: tool.description,
});

export const formatSummaryList = (tools: ToolSummary[]): string =>
  tools
    .map(
      (tool) =>
        `- ${tool.name} [${tool.group}, tier ${tool.safety.tier} ${tool.safety.label}]\n  ${tool.description}`
    )
    .join("\n");

export const formatToolContract = (tool: ToolDef): string => {
  const related = tool.relatedTools?.length ? tool.relatedTools.join(", ") : "none";
  return [
    `# ${tool.name}`,
    "",
    `Title: ${tool.title}`,
    `Group: ${tool.group}`,
    `Safety: tier ${tool.safety.tier} (${tool.safety.label}) - ${tool.safety.description}`,
    "",
    "Description:",
    tool.description,
    "",
    "Arguments:",
    tool.argsDescription,
    "",
    "Example invoke_tool call:",
    "```json",
    JSON.stringify({ name: tool.name, args: tool.exampleArgs }, null, 2),
    "```",
    "",
    "Common failures:",
    ...tool.commonFailures.map((failure) => `- ${failure}`),
    "",
    `Related tools: ${related}`,
  ].join("\n");
};

export const formatSearchResults = (tools: ToolDef[]): string => {
  if (tools.length === 0) {
    return "No matching enabled Designflow MCP capabilities found. Try broader terms like api, rfq, item, image, sample, factory, grid, or tracking.";
  }

  return tools.map(formatToolContract).join("\n\n---\n\n");
};


