import type { z } from "zod/v4";
import type { DesignflowClient } from "./clients/designflow-client.js";

export type SafetyTier = 1 | 2 | 3;

export type ToolGroup =
  | "company_context"
  | "api_docs"
  | "core"
  | "item_master"
  | "tracking"
  | "data_sync"
  | "images"
  | "admin";

export type ToolSafety = {
  tier: SafetyTier;
  label: string;
  description: string;
};

export type CapabilityGroup = {
  name: ToolGroup;
  description: string;
};

export type InvokeContext = {
  client: DesignflowClient;
  cwd: string;
};

export type ToolDef<TArgs extends z.ZodObject<any> = z.ZodObject<any>> = {
  name: string;
  title: string;
  group: ToolGroup;
  safety: ToolSafety;
  description: string;
  argsDescription: string;
  argsSchema: TArgs;
  exampleArgs: z.infer<TArgs>;
  commonFailures: string[];
  relatedTools?: string[];
  invoke: (args: z.infer<TArgs>, context: InvokeContext) => Promise<unknown>;
};

export type ToolSummary = {
  name: string;
  title: string;
  group: ToolGroup;
  safety: ToolSafety;
  description: string;
};

